import{_ as r,c as a,o,ae as t}from"./chunks/framework.DJYebpIC.js";const p=JSON.parse('{"title":"Errors","description":"","frontmatter":{},"headers":[],"relativePath":"en/reference/errors.md","filePath":"en/reference/errors.md"}'),s={name:"en/reference/errors.md"};function n(i,e,l,c,d,h){return o(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="errors" tabindex="-1">Errors <a class="header-anchor" href="#errors" aria-label="Permalink to &quot;Errors {#errors}&quot;">​</a></h1><p><code>asyncmux</code> custom error classes are designed with internationalization (i18n) in mind, built upon the <code>i18n-error-base</code> framework.</p><h2 id="error-base" tabindex="-1"><code>ErrorBase</code> <a class="header-anchor" href="#error-base" aria-label="Permalink to &quot;`ErrorBase` {#error-base}&quot;">​</a></h2><p>This is the base class for all <code>asyncmux</code> errors. It extends <code>I18nErrorBase</code> from <code>i18n-error-base</code>, providing support for errors with metadata and localized messages.</p><h2 id="unreachable-error" tabindex="-1"><code>UnreachableError</code> <a class="header-anchor" href="#unreachable-error" aria-label="Permalink to &quot;`UnreachableError` {#unreachable-error}&quot;">​</a></h2><p>An error used when &quot;unreachable code&quot; is executed. It is primarily used for exhaustiveness checking (the <code>never</code> type) or ensuring an exhaustive <code>switch</code> statement.</p><h3 id="unreachable-metadata" tabindex="-1">Metadata <a class="header-anchor" href="#unreachable-metadata" aria-label="Permalink to &quot;Metadata {#unreachable-metadata}&quot;">​</a></h3><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  value</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">?:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> unknown;</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><strong><code>value</code></strong></p><ul><li><strong>Type</strong>: <code>unknown</code></li></ul><p>The value that was supposed to be unreachable.</p><h3 id="unreachable-troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#unreachable-troubleshooting" aria-label="Permalink to &quot;Troubleshooting {#unreachable-troubleshooting}&quot;">​</a></h3><p>If this error occurs at runtime, it likely indicates that the user is utilizing <code>asyncmux</code> in a non-type-safe manner, or there is a bug within <code>asyncmux</code> itself.</p><h2 id="decorator-support-error" tabindex="-1"><code>DecoratorSupportError</code> <a class="header-anchor" href="#decorator-support-error" aria-label="Permalink to &quot;`DecoratorSupportError` {#decorator-support-error}&quot;">​</a></h2><p>An error thrown when the runtime environment does not support Stage 3 decorators.</p><h3 id="decorator-support-troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#decorator-support-troubleshooting" aria-label="Permalink to &quot;Troubleshooting {#decorator-support-troubleshooting}&quot;">​</a></h3><p>You must use a runtime environment that supports Stage 3 decorators or provide a polyfill/implementation that simulates them.</p><h2 id="lock-escalation-error" tabindex="-1"><code>LockEscalationError</code> <a class="header-anchor" href="#lock-escalation-error" aria-label="Permalink to &quot;`LockEscalationError` {#lock-escalation-error}&quot;">​</a></h2><p>An error thrown when an attempt is made to perform lock escalation (upgrading from a <code>read</code> lock to a <code>write</code> lock).</p><h3 id="lock-escalation-troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#lock-escalation-troubleshooting" aria-label="Permalink to &quot;Troubleshooting {#lock-escalation-troubleshooting}&quot;">​</a></h3><p>This is a design constraint intended to prevent deadlocks. Please consider the following:</p><ul><li>Review and refactor your implementation.</li><li>Decouple sections that can be executed in parallel.</li></ul>',22)])])}const b=r(s,[["render",n]]);export{p as __pageData,b as default};
